// BTZ_Trips_Search_AI_SAFE - Reducer v2 (AI-SAFE)
// Mejora: toma departureTime real, convierte precio a MXN, shortId útil

const maxN = (() => {
  const raw = $json.maxResults ?? "3";
  const n = parseInt(String(raw), 10);
  return Number.isFinite(n) && n > 0 ? Math.min(n, 10) : 3;
})();

// Detectar body (por si viene envuelto)
const body = (() => {
  if ($json?.trips) return $json;
  if ($json?.data?.trips) return $json.data;
  if (Array.isArray($json) && $json[0]?.trips) return $json[0];
  return $json;
})();

const departures = body?.trips?.departures ?? [];

const toStr = (v) => (v ?? "") + "";

// Heurística para price -> MXN
function toMxn(priceRaw) {
  if (priceRaw === null || priceRaw === undefined) return null;
  const n = Number(priceRaw);
  if (!Number.isFinite(n)) return null;

  // casos típicos:
  // 1399.00 ya viene bien
  if (n < 100000) return n;

  // 139900000 -> 1399.00 (div 100000)
  if (n >= 1000000) return n / 100000;

  // fallback conservador
  return n;
}

const options = departures.slice(0, maxN).map((d, idx) => {
  const depId = toStr(d.id);

  const depTime =
    toStr(d.departureTime) ||
    toStr(d?.segments?.[0]?.time) ||
    "";

  const arrTime =
    toStr(d.arrivalTime) ||
    "";

  const duration =
    d?.duration ??
    d?.durationInMinutes ??
    "";

  const priceRaw =
    d?.prices?.[0]?.amount ??
    d?.price?.amount ??
    d?.price ??
    null;

  const priceMxn = toMxn(priceRaw);

  const last8 = depId ? depId.slice(-8) : "";
  const depShort = depTime && last8 ? `${depTime}-${last8}` : (depId ? depId.slice(0, 16) : "");

  return {
    option: idx + 1,
    departureId: depId,
    departureIdShort: depShort,
    departureTime: depTime,
    arrivalTime: arrTime,
    duration,
    priceMxn: priceMxn,     // número (ej. 1399)
    priceRaw: priceRaw      // para auditoría
  };
});

return [
  {
    json: {
      _debug: {
        departuresCount: departures.length,
        maxResults: maxN
      },
      options,
      firstDepartureId: options?.[0]?.departureId ?? ""
    }
  }
];
